const c = $input.first().json;
const BASE = 'https://whizz.aiingo.com';
const TOKEN = 'nc_pat_n5dMpFolDUQNtkCWGiCJnX45xXWUoFnZdsQkwEyF';
const clientId = c.client_id;
const headers = { 'xc-token': TOKEN };

let tableMap = {};
const configured = c.ta_table_ids || {};
if (configured.packages || configured.umrah_groups || configured.cars || configured.itineraries) {
  tableMap = configured;
} else {
  try {
    const basesResp = await $http.request({ method: 'GET', url: `${BASE}/api/v2/meta/bases`, headers });
    const TA_NAMES = ['packages', 'umrah_groups', 'cars', 'itineraries'];
    for (const base of (basesResp.list || [])) {
      if (Object.keys(tableMap).length === TA_NAMES.length) break;
      const tResp = await $http.request({ method: 'GET', url: `${BASE}/api/v2/meta/bases/${base.id}/tables`, headers }).catch(() => ({ list: [] }));
      for (const t of (tResp.list || [])) {
        const key = t.title.toLowerCase().replace(/\s+/g, '_');
        if (TA_NAMES.includes(key) && !tableMap[key]) tableMap[key] = t.id;
      }
    }
  } catch(e) {}
}

async function fetchTable(tableId, extra = '') {
  if (!tableId) return [];
  try {
    const r = await $http.request({ method: 'GET', url: `${BASE}/api/v2/tables/${tableId}/records?where=(client_id,eq,${clientId})${extra}&limit=30`, headers });
    return r.list || [];
  } catch(e) { return []; }
}

const today = new Date().toISOString().slice(0, 10);
const [packages, umrahGroups, cars, itineraries] = await Promise.all([
  fetchTable(tableMap.packages),
  fetchTable(tableMap.umrah_groups, '&sort=departure_date'),
  fetchTable(tableMap.cars, '~and(status,eq,available)'),
  fetchTable(tableMap.itineraries)
]);

return [{ json: { ...c, packages, umrahGroups: umrahGroups.filter(g => g.departure_date >= today), cars, itineraries } }];

const input = $input.first().json;
const { packages, umrahGroups, cars, itineraries } = input;
let block = '';

if (packages && packages.length) {
  const lines = packages.map(p => {
    let l = `- ${p.name}`;
    if (p.destination) l += ` | Destination: ${p.destination}`;
    if (p.nights) l += ` | ${p.nights} nights`;
    if (p.type) l += ` | Type: ${p.type}`;
    if (p.sell_price || p.base_price) l += ` | Price: ${p.currency||'INR'} ${p.sell_price||p.base_price}/person`;
    if (p.pax_min || p.pax_max) l += ` | Pax: ${p.pax_min||1}-${p.pax_max||''}`;
    try { const inc=JSON.parse(p.inclusions||'[]'); if(inc.length) l += ` | Includes: ${inc.join(', ')}`; } catch(e){}
    return l;
  }).join('\n');
  block += '\n\n## Travel Packages\n' + lines;
}

if (umrahGroups && umrahGroups.length) {
  const lines = umrahGroups.map(g => `- ${g.name} | Departs: ${g.departure_date} | Seats: ${g.seats||0} | ${g.currency||'INR'} ${g.price_per_pax||''}/person`).join('\n');
  block += '\n\n## Upcoming Umrah / Hajj Groups\n' + lines;
}

if (itineraries && itineraries.length) {
  const lines = itineraries.map(it => {
    let days = []; try { days = JSON.parse(it.days||'[]'); } catch(e) {}
    return `- ${it.title}${it.destination?' | '+it.destination:''} | ${days.length} days`;
  }).join('\n');
  block += '\n\n## Itineraries\n' + lines;
}

if (cars && cars.length) {
  const lines = cars.map(c => `- ${c.name}${c.category?' ('+c.category+')':''} | ${c.seats||'?'} seats | ${c.currency||'INR'} ${c.daily_rate||0}/day${c.plate_no?' | Plate: '+c.plate_no:''}`).join('\n');
  block += '\n\n## Available Cars for Rent\n' + lines;
}

return [{ json: { ...input, taContextBlock: block } }];
